// Parse Lightspeed jobs from HTML
const items = $input.all();
const html = String(items[0]?.json?.data || items[0]?.json || '');
const results = [];
const seen = new Set();
const today = new Date().toISOString().split('T')[0];

// CX-relevant keywords
const cxKeywords = ['customer', 'support', 'success', 'experience', 'cx', 'service', 'solutions', 'implementation', 'onboarding', 'account manager', 'technical account', 'client'];

// Split by job card boundaries - actual class is job-list-job
const cards = html.split(/class="job-list-job"/);

for (const card of cards) {
  // Extract job title from h2.job-list-job-title > a
  const titleMatch = card.match(/class="job-list-job-title"[^>]*>[\s\S]*?<a[^>]*>([^<]+)</);
  if (!titleMatch) continue;
  const title = titleMatch[1].trim();

  // Filter for CX-relevant roles
  const titleLower = title.toLowerCase();
  const isCxRelevant = cxKeywords.some(kw => titleLower.includes(kw));
  if (!isCxRelevant) continue;

  // Extract company name from a.job-list-job-company-link
  const companyMatch = card.match(/class="job-list-job-company-link"[^>]*>([^<]+)</);
  const company = companyMatch ? companyMatch[1].trim() : '';

  // Extract job URL from anchor inside title h2
  const urlMatch = card.match(/class="job-list-job-title"[^>]*>[\s\S]*?<a[^>]*href="([^"]+)"/);
  const jobUrl = urlMatch ? urlMatch[1] : '';

  // Extract location from span with job-list-badge-locations class
  const locationMatch = card.match(/class="[^"]*job-list-badge-locations[^"]*"[^>]*>([^<]+)</);
  const location = locationMatch ? locationMatch[1].trim() : 'Remote';

  // Generate Job ID from URL or company+title
  let jobId = '';
  if (jobUrl) {
    const urlParts = jobUrl.split('/');
    jobId = 'lsvp-' + urlParts[urlParts.length - 1].substring(0, 20);
  } else {
    jobId = 'lsvp-' + (company + '-' + title).toLowerCase().replace(/[^a-z0-9]/g, '').substring(0, 20);
  }

  // Dedup by company+title
  const key = (company + ':' + title).toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seen.has(key)) continue;
  seen.add(key);

  results.push({
    json: {
      'Job Title': title,
      'Job URL': jobUrl,
      'Company': company,
      'Location': location,
      'Source': 'Lightspeed',
      'Source Detail': 'lightspeed-jobs-board',
      'Date Found': today,
      'Job ID': jobId,
      'Salary Info': ''
    }
  });
}

if (results.length === 0) {
  const hasJobItems = html.includes('job-list-job');
  return [{ json: { _empty: true, _message: 'No CX jobs found', htmlLength: html.length, hasJobItems: hasJobItems } }];
}

return results;
